#include <iostream>
#include <string.h>
#include <cmath>
using namespace std;
#include <iostream>
#include <string>
using namespace std;

string removeDuplicates(string s) {
    string result;
    for (char c : s) {
        if (!result.empty() && result.back() == c) {
            result.pop_back();
        } else {
            result.push_back(c);
        }
    }
    return result;
}

int main() {
    string s = "abbaca";
    string result = removeDuplicates(s);
    cout << result << endl;
    return 0;
}

